import{_ as a,o as r,c as e,ag as o,ah as n}from"./chunks/framework.D9bIGSBm.js";const u=JSON.parse('{"title":"子智能体","description":"","frontmatter":{},"headers":[],"relativePath":"features/subagents.md","filePath":"features/subagents.md"}'),s={name:"features/subagents.md"};function l(d,t,i,h,g,p){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="子智能体" tabindex="-1">子智能体 <a class="header-anchor" href="#子智能体" aria-label="Permalink to &quot;子智能体&quot;">​</a></h1><p>子智能体（Sub-agent）是由主 Agent 派生出来的专项 Agent——主 Agent 在处理复杂任务时，可以将某个子任务交给子智能体独立执行，子任务完成后结果汇总回主流程。</p><blockquote><p>相关基础：<a href="/docs/features/conversation.html#工具调用卡片">对话面板 → 子 Agent 子卡片</a></p></blockquote><div class="tip custom-block"><p class="custom-block-title">一个类比</p><p>可以把它想象成：AI 面对一个大工程时，自动雇了几位「专项小助手」分头干活——有人专门查资料、有人专门改代码——各自干完后向主 AI 汇报结果，主 AI 再汇总推进。</p></div><hr><h2 id="对话中的子智能体卡片" tabindex="-1">对话中的子智能体卡片 <a class="header-anchor" href="#对话中的子智能体卡片" aria-label="Permalink to &quot;对话中的子智能体卡片&quot;">​</a></h2><h3 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h3><p>每当主 Agent 派生一个子智能体，对话区会出现一张<strong>折叠子卡片</strong>，将子智能体的完整对话过程封装在其中。</p><h3 id="怎么看" tabindex="-1">怎么看 <a class="header-anchor" href="#怎么看" aria-label="Permalink to &quot;怎么看&quot;">​</a></h3><p>子卡片的标题行显示子任务的基本信息与运行状态：</p><ul><li><strong>运行中</strong>：标题右侧出现三点滚动动效（<code>···</code>），表示子 Agent 正在工作</li><li><strong>已完成</strong>：状态图标变为灰色对勾（✓）</li><li><strong>出错</strong>：状态图标变为红色叉号（✗）</li></ul><p>子卡片默认<strong>折叠</strong>，点击标题行（或按 Enter / Space）可展开查看子 Agent 的完整输出，再次点击收起。展开后可以看到：</p><ul><li>子任务的提示摘要（来自发送给子 Agent 的 prompt）</li><li>子 Agent 产生的 thinking 块、回复内容与工具调用</li></ul><p>若子 Agent 尚未产生任何输出，展开后会显示占位提示「等待子 Agent 输出…」。</p><p><img src="'+n+'" alt="截图：对话面板中一张子 Agent 子卡片处于折叠状态，标题行显示运行中三点动效；右侧箭头图标提示可展开"></p><hr><h2 id="设置-→-子智能体" tabindex="-1">设置 → 子智能体 <a class="header-anchor" href="#设置-→-子智能体" aria-label="Permalink to &quot;设置 → 子智能体&quot;">​</a></h2><h3 id="这是什么-1" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么-1" aria-label="Permalink to &quot;这是什么&quot;">​</a></h3><p><strong>设置 → 子智能体</strong>页面是自定义子智能体的可视化管理中心，你可以在这里新建、编辑、启用/禁用、删除用户级和项目级子智能体，也可以查看插件提供的子智能体。</p><p>子智能体按作用域分为三类：</p><table tabindex="0"><thead><tr><th>标签</th><th>含义</th></tr></thead><tbody><tr><td><strong>用户</strong></td><td>跨项目可用，存储在用户配置目录</td></tr><tr><td><strong>项目</strong></td><td>仅当前工作区可用（需有活动工作区）</td></tr><tr><td><strong>Plugin</strong>（界面原文）</td><td>由插件提供，因此只读，需在插件侧修改</td></tr></tbody></table><h3 id="在哪里打开" tabindex="-1">在哪里打开 <a class="header-anchor" href="#在哪里打开" aria-label="Permalink to &quot;在哪里打开&quot;">​</a></h3><p><strong>设置</strong>（右上角齿轮图标）→ 左侧导航 → <strong>子智能体</strong></p><h3 id="新建子智能体" tabindex="-1">新建子智能体 <a class="header-anchor" href="#新建子智能体" aria-label="Permalink to &quot;新建子智能体&quot;">​</a></h3><ol><li><p>点击右上角<strong>新建子智能体</strong>按钮，打开新建表单。</p></li><li><p>填写以下字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>只能包含字母、数字和连字符，长度 3–50 个字符</td></tr><tr><td><strong>颜色</strong></td><td>子智能体标识颜色（可选）</td></tr><tr><td><strong>作用域</strong></td><td>用户 / 项目（选项取决于是否有活动工作区）</td></tr><tr><td><strong>描述</strong></td><td>简要说明该子智能体的用途</td></tr><tr><td><strong>系统提示词</strong></td><td>指导子智能体行为的核心指令</td></tr><tr><td><strong>工具</strong></td><td>允许该子智能体使用的工具分组；不选则不限制，继承全部工具</td></tr><tr><td><strong>模型</strong></td><td>下拉选择，选项有 inherit、opus、sonnet、haiku；选 inherit 表示继承当前会话模型（选择器下方有提示「inherit 继承当前会话模型」）</td></tr></tbody></table></li><li><p>填写完成后点击<strong>保存</strong>，页面自动返回列表，新建的子智能体出现在列表中并提示「已新建 {name}」。</p></li></ol><h3 id="编辑子智能体" tabindex="-1">编辑子智能体 <a class="header-anchor" href="#编辑子智能体" aria-label="Permalink to &quot;编辑子智能体&quot;">​</a></h3><ol><li>在列表中找到目标子智能体，点击进入详情。</li><li>详情页显示名称、描述、系统提示词、作用域、状态、模型、工具、文件路径等所有字段。</li><li>点击<strong>编辑</strong>进入编辑表单，修改后保存即可，提示「已保存 {name}」。</li></ol><h3 id="启用-禁用" tabindex="-1">启用 / 禁用 <a class="header-anchor" href="#启用-禁用" aria-label="Permalink to &quot;启用 / 禁用&quot;">​</a></h3><p>在列表中切换每条子智能体右侧的开关，状态立即变为<strong>已启用</strong>或<strong>已禁用</strong>。被禁用的子智能体不会被主 Agent 调用。</p><h3 id="删除子智能体" tabindex="-1">删除子智能体 <a class="header-anchor" href="#删除子智能体" aria-label="Permalink to &quot;删除子智能体&quot;">​</a></h3><p>在详情页点击删除，弹出确认对话框：</p><blockquote><p>「确定删除「{name}」？文件将移入回收站。」</p></blockquote><p>确认后文件移入系统回收站，列表刷新并提示「已删除 {name}」。</p><div class="tip custom-block"><p class="custom-block-title">项目级子智能体需有活动工作区</p><p>新建「项目」作用域的子智能体时，需要先在主界面打开一个工作区，否则选项置灰并提示「需有活动工作区」。</p></div><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>了解子智能体之后，可以继续了解 LoongCode 的权限体系，前往<a href="/docs/features/permissions.html">权限管理</a>继续学习。</p>',37)])])}const b=a(s,[["render",l]]);export{u as __pageData,b as default};
